import requests
from urllib.parse import urlparse, urlunparse
import json

# Configuration parameters
username = 'guest'
password = 'guest'
host = 'localhost'
port = 15672
vhosts = {
    'app1': {'user': 'app1_user', 'pass': 'app1_pass'},
    'app2': {'user': 'app2_user', 'pass': 'app2_pass'},
    # Add more applications as needed
}

# Create RabbitMQ management API URL
base_url = f'http://{username}:{password}@{host}:{port}/api/'
url_path = urlparse(base_url).path

def create_vhost(vhost):
    url = base_url + url_path + f'vhosts/{vhost}'
    response = requests.put(url, auth=(username, password))
    if response.status_code == 201:
        print(f'VHost {vhost} created successfully')
    else:
        print(f'Error creating VHost {vhost}')

def create_user(vhost, user):
    url = base_url + url_path + f'users/{user}'
    data = {
        'password': user['pass'],
        'tags': 'management',
        'vhosts': [vhost],
        'permissions': {
            'vhosts': {
                vhost: [
                    '.*',  # Allow all operations on this VHost
                ]
            }
        }
    }
    response = requests.put(url, auth=(username, password), data=json.dumps(data))
    if response.status_code == 201:
        print(f'User {user["pass"]} created successfully in VHost {vhost}')
    else:
        print(f'Error creating user {user["pass"]} in VHost {vhost}')

# Create vhosts and users
for app, user_pass in vhosts.items():
    create_vhost(app)
    create_user(app, {'user': user_pass['user'], 'pass': user_pass['pass']})